"""Display DPI detection and Tkinter scaling for HiDPI support.

On Linux/Wayland, Tkinter runs through XWayland and does not pick up the
compositor's display scale factor.  This module detects the effective DPI
of the current screen and adjusts ``tk scaling`` so that point-based font
sizes render at the correct physical size.

Detection order (first match wins):
1. ``--scale`` CLI arg  (passed as *override*)
2. ``CLAUDE_DASHBOARD_SCALE`` env var
3. Physical screen DPI from Tkinter screen metrics  (Linux only)
4. ``Xft.dpi`` from X resources                     (Linux only)
5. No adjustment (factor 1.0)
"""

import logging
import os
import subprocess
import tkinter as tk

from claude_dashboard import config

logger = logging.getLogger(__name__)

# Minimum DPI ratio to trigger scaling.  Avoids jitter from slightly
# inaccurate EDID or rounding (e.g. 102 DPI on a 96-DPI-baseline screen).
_SCALE_THRESHOLD = 1.2

# Baseline DPI that Tk/X11 defaults to when nothing else is configured.
_BASELINE_DPI = 96.0


def _screen_physical_dpi(root: tk.Tk) -> float | None:
    """Compute physical DPI from Tkinter screen width (px) and size (mm)."""
    try:
        mm_w = root.winfo_screenmmwidth()
        px_w = root.winfo_screenwidth()
        if mm_w > 0 and px_w > 0:
            dpi = px_w / (mm_w / 25.4)
            logger.debug("screen metrics: %dpx / %dmm = %.0f DPI", px_w, mm_w, dpi)
            return dpi
    except Exception:
        pass
    return None


def _xft_dpi() -> float | None:
    """Read ``Xft.dpi`` from X resources via ``xrdb``."""
    try:
        result = subprocess.run(
            ["xrdb", "-query"],
            capture_output=True,
            text=True,
            timeout=2,
            creationflags=config.SUBPROCESS_FLAGS,
        )
        if result.returncode == 0:
            for line in result.stdout.splitlines():
                if line.strip().startswith("Xft.dpi"):
                    dpi = float(line.split(":")[-1].strip())
                    logger.debug("Xft.dpi: %.0f", dpi)
                    return dpi
    except Exception:
        pass
    return None


def detect_scale_factor(root: tk.Tk) -> float:
    """Return the multiplier to apply to ``tk scaling``.

    A return value of 1.0 means no additional scaling is needed.
    """
    # --- explicit override via env var ---
    env_val = os.environ.get("CLAUDE_DASHBOARD_SCALE")
    if env_val:
        try:
            factor = float(env_val)
            logger.info("CLAUDE_DASHBOARD_SCALE override: %.2f", factor)
            return factor
        except ValueError:
            logger.warning("invalid CLAUDE_DASHBOARD_SCALE value: %s", env_val)

    if not config.IS_LINUX:
        return 1.0

    # What Tk currently thinks DPI is (derived from tk scaling).
    tk_dpi = float(root.tk.call("tk", "scaling")) * 72

    # --- physical DPI from screen metrics ---
    phys_dpi = _screen_physical_dpi(root)
    if phys_dpi is not None and phys_dpi > _BASELINE_DPI:
        factor = phys_dpi / max(tk_dpi, _BASELINE_DPI)
        if factor >= _SCALE_THRESHOLD:
            logger.info(
                "physical DPI %.0f vs tk DPI %.0f → scale factor %.2f",
                phys_dpi,
                tk_dpi,
                factor,
            )
            return factor

    # --- Xft.dpi fallback ---
    xdpi = _xft_dpi()
    if xdpi is not None and xdpi > _BASELINE_DPI:
        factor = xdpi / max(tk_dpi, _BASELINE_DPI)
        if factor >= _SCALE_THRESHOLD:
            logger.info(
                "Xft.dpi %.0f vs tk DPI %.0f → scale factor %.2f",
                xdpi,
                tk_dpi,
                factor,
            )
            return factor

    return 1.0


def apply_dpi_scaling(root: tk.Tk, *, override: float | None = None) -> float:
    """Detect and apply DPI scaling to the Tk root window.

    Must be called after ``tk.Tk()`` but before creating widgets.

    Returns the effective scale factor — the ratio of the final tk scaling
    to the 96 DPI baseline (1.333).  This accounts for BOTH system-level
    scaling (e.g. GNOME 200% on Wayland setting tk scaling high before we
    run) and any additional correction we apply.
    """
    current = float(root.tk.call("tk", "scaling"))
    logger.debug("default tk scaling: %.3f (%.0f DPI)", current, current * 72)

    factor = override if override is not None else detect_scale_factor(root)

    if abs(factor - 1.0) >= 0.05:
        new_scaling = current * factor
        root.tk.call("tk", "scaling", new_scaling)
        logger.info(
            "applied DPI scale %.2fx (tk scaling %.3f → %.3f, effective DPI %.0f)",
            factor,
            current,
            new_scaling,
            new_scaling * 72,
        )

    baseline = _BASELINE_DPI / 72.0
    final_scaling = float(root.tk.call("tk", "scaling"))
    effective = final_scaling / baseline
    if effective < _SCALE_THRESHOLD:
        logger.debug("effective scale %.2f below threshold, treating as 1.0", effective)
        return 1.0

    logger.info("effective pixel scale factor: %.2f", effective)
    return effective
